firmware_template.source:
#include "dumbdisplay_wifi.h"
#include <WiFi.h>
#include "dumbdisplay.h"
#include "wifidumbdisplay.h"

static DDWiFiServerIO* ddio = nullptr;
static DumbDisplay* dd = nullptr;
static LcdDDLayer* lcd = nullptr;
static LedGridDDLayer* ledGrid = nullptr;
static GraphicalDDLayer* gfx = nullptr;
static TurtleDDLayer* turtle = nullptr;

void dd_wifi_setup(const char* ssid, const char* password) {
  WiFi.begin(ssid, password);
  while (WiFi.status() != WL_CONNECTED) { delay(500); }
  Serial.print("[dd] IP: "); Serial.println(WiFi.localIP());
  ddio = new DDWiFiServerIO(nullptr, nullptr, 10201);
  dd = new DumbDisplay(ddio);
}

void dd_wifi_loop() { /* DumbDisplay handles its own loop internally */ }

void dd_create_lcd(int cols, int rows) {
  lcd = dd->createLcdLayer(cols, rows);
}

void dd_create_led_grid(int cols, int rows) {
  ledGrid = dd->createLedGridLayer(cols, rows);
}

void dd_create_graphical(int width, int height) {
  gfx = dd->createGraphicalLayer(width, height);
}

void dd_create_turtle(int width, int height) {
  turtle = dd->createTurtleLayer(width, height);
}

void dd_lcd_print(int col, int row, const char* text) {
  if (!lcd) return;
  lcd->setCursor(col, row);
  lcd->print(text);
}

void dd_lcd_clear() {
  if (!lcd) return;
  lcd->clear();
}

void dd_led_set(int col, int row, const char* color) {
  if (!ledGrid) return;
  ledGrid->onColor(color);
  ledGrid->turnOn(col, row);
}

void dd_gfx_line(int x1, int y1, int x2, int y2, const char* color) {
  if (!gfx) return;
  gfx->drawLine(x1, y1, x2, y2, color);
}

void dd_gfx_rect(int x, int y, int w, int h, const char* color, bool fill) {
  if (!gfx) return;
  if (fill) gfx->fillRect(x, y, w, h, color);
  else gfx->drawRect(x, y, w, h, color);
}

void dd_gfx_circle(int x, int y, int r, const char* color, bool fill) {
  if (!gfx) return;
  if (fill) gfx->fillCircle(x, y, r, color);
  else gfx->drawCircle(x, y, r, color);
}

void dd_gfx_text(int x, int y, const char* text, const char* color, int size) {
  if (!gfx) return;
  gfx->setTextColor(color);
  gfx->setTextSize(size);
  gfx->drawStr(x, y, text);
}

void dd_turtle_forward(int steps) {
  if (!turtle) return;
  turtle->forward(steps);
}

void dd_turtle_turn(int degrees) {
  if (!turtle) return;
  turtle->rightTurn(degrees);
}

void dd_turtle_pencolor(const char* color) {
  if (!turtle) return;
  turtle->penColor(color);
}

void dd_auto_pin(const char* layout) {
  dd->configAutoPin(layout);
}
